sql:
SELECT hospital_id
FROM hospital_specialties
WHERE specialty = 'cardiology';

SELECT hospital_id, MAX(rate) AS highest_mortality_rate
FROM mortality_rates
GROUP BY hospital_id;

SELECT DISTINCT hospital_type
FROM hospitals
ORDER BY hospital_type;

SELECT hospital_id, AVG(rating) as average_satisfaction, COUNT(*) as number_of_surveys
FROM patient_satisfaction
GROUP BY hospital_id;

SELECT h.name
FROM hospitals h
JOIN hospital_ratings hr ON h.hospital_id = hr.hospital_id
WHERE hr.overall_rating = (
  SELECT MAX(overall_rating) FROM hospital_ratings
);

SELECT AVG(rate) AS average_mortality_rate
FROM mortality_rates
WHERE condition = 'pneumonia';

SELECT hospital_id, AVG(patient_satisfaction_rating) AS average_patient_satisfaction
FROM hospital_ratings
GROUP BY hospital_id;

external_knowledge:
Performance index formula: (100 - mortality rate + 100 - readmission rate + patient satisfaction) / 3; 
The last three years refer to the most recent three distinct years available in the data; 
Inverse of the rates is used to prioritize hospitals with lower mortality and readmission rates.

